const MyRoom = ({ student, rooms }) => {
  const room = rooms.find(r => r.id === student?.roomId);
  return (
    <div>
      <h2 style={{ fontSize: 22, fontWeight: 800, color: "#1e293b", marginBottom: 24 }}>🛏️ My Room</h2>
      {!room ? (
        <div style={{ background: "#fff", borderRadius: 16, padding: 32, boxShadow: "0 2px 16px rgba(30,41,59,0.07)", textAlign: "center" }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🏠</div>
          <h3 style={{ color: "#1e293b", marginBottom: 8 }}>No Room Assigned</h3>
          <p style={{ color: "#64748b" }}>Browse rooms and request one from the Rooms section.</p>
        </div>
      ) : (
        <div style={{ background: "#fff", borderRadius: 16, padding: 28, boxShadow: "0 2px 16px rgba(30,41,59,0.07)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <h3 style={{ margin: 0, fontSize: 24, fontWeight: 800, color: "#1e293b" }}>Room {room.id}</h3>
            <span style={{ background: "#dcfce7", color: "#15803d", padding: "4px 12px", borderRadius: 99, fontSize: 13, fontWeight: 600 }}>
              ✅ Assigned
            </span>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
            {[["Block", room.block], ["Floor", room.floor], ["Type", room.type], ["Capacity", room.capacity]].map(([k, v]) => (
              <div key={k} style={{ background: "#f8fafc", borderRadius: 12, padding: "14px 18px" }}>
                <div style={{ fontSize: 12, color: "#64748b", marginBottom: 4 }}>{k}</div>
                <div style={{ fontSize: 18, fontWeight: 700, color: "#1e293b" }}>{v}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default MyRoom;
